var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"보람 있는 학창 생활을 보내고 계신가요, 고등부 학생 여러분?","JPN":"高等部の皆様、楽しい学校生活を送られていますか？","ENG":"I hope you're all making the most of your time at the Academy, everyone!","TWN":"各位高等部同學，你們的學校生活過的充實嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"아카데미 총학생회장, 옌 싱 란체스터입니다.","JPN":"アカデミー生徒会長、イェン・シング・ランチェスターです。","ENG":"This is Yen Xing Lanchester, Student President of the Academy.","TWN":"我是學院學生會的會長嫣杏·蘭賈斯特。"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"목적지에 도착하기 전에, 오늘 실시될 다이브 실전 훈련을 안내해 드리도록 하죠.","JPN":"目的地に着く前に、本日実施されるダイブ実戦訓練についてご案内します。","ENG":"Before we reach the destination, I'd like to run you through the Dive training planned for today.","TWN":"在到達目的地之前，我先給大家講解下躍入實戰訓練。"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"여러분은 지금부터 이면세계로 다이브해서, 그 일대의 하급 침식체를 상대하게 될 거예요.","JPN":"皆様はこれから裏世界にダイブし、その一帯の下級侵食体を相手に戦うことになります。","ENG":"You'll be diving into the Counterside to face off with the lower ranking C.O.s in the area.","TWN":"大家現在開始將躍入異界，與附近的下類侵蝕體進行戰鬥。"},"stage":{"bg":"MAINSTREAM_5201003","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"물론 2종 이상의 침식체는 관리국이 파견한 태스크포스가 격퇴했으니 안심해도 돼요.","JPN":"もちろん第2種以上の侵食体は管理局が派遣したタスクフォースカンパニーが掃討しているので安心してください。","ENG":"Rest assured, you won't have to worry about anything beyond Category 1, as the Administration already sanitized the area.","TWN":"當然，2類以上的侵蝕體已經被管理局派出的特遣勢力消滅了，所以不用擔心。"},"stage":{"bg":"MAINSTREAM_5201003","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"각자의 훈련 점수는 훈련 중 격퇴한 침식체의 수와 위험도에 따라 책정됩니다.","JPN":"各自の訓練点数は訓練中に撃退した侵食体の数や危険度によって査定されます。","ENG":"Your score will be based on the number and threat level of the C.O.s you slay during the mission.","TWN":"各自的訓練分數會根據訓練中消滅的侵蝕體數量和危險程度來計算。"},"stage":{"bg":"MAINSTREAM_5201001","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"특히 고득점자는 졸업을 위한 전투 훈련을 수료한 것으로 인정된다더군요.","JPN":"特に高得点者は卒業のための戦闘訓練を修了したと認められるそうですね。","ENG":"If you're among the top scorers, you can even have the combat training requirement for graduation waivered.","TWN":"特別是得到高分的人將被視為已完成畢業之前的戰鬥訓練。"},"stage":{"bg":"MAINSTREAM_5201001","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"총학생회도 격려차 소정의 부상을 준비해 두었으니, 모두 분발해 주시길.","JPN":"生徒会も皆様のモチベーションのために所定の副賞を用意しておりますので、どうか奮起してください。","ENG":"The Student Council has also prepared a modest set of rewards as an extra incentive, so I hope you'll all try your best out there.","TWN":"學院學生會也準備了一定數量的獎品作為鼓勵，希望大家能夠全力以赴。"},"stage":{"bg":"MAINSTREAM_5201001","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"선배, 방금 회장님이 한 얘기 들었어요?","JPN":"先輩、さっきの会長の話聞きました？","ENG":"Ray, did you hear what the Student Council President just said?","TWN":"前輩，你聽到剛才學生會長說的話了嗎？"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"이번 훈련에서 고득점을 내면 전투 훈련을 더 안 받아도 된대요!","JPN":"今回の訓練で高得点を出せば、戦闘訓練をこれ以上受けなくてもいいらしいですよ！","ENG":"If you score high on this training mission, you won't have to complete any more combat training!","TWN":"如果在這次訓練得到高分，你就不用再完成戰鬥訓練了。"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"전투 훈련만 아니면 선배도 분명 졸업할 수 있을 거예요!","JPN":"戦闘訓練さえなければ、先輩もきっと卒業できますよね？","ENG":"With that requirement out of the way, you should finally be able to graduate!","TWN":"只要沒有戰鬥訓練拖後腿，前輩就能畢業了！"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_NULL","text":{"KOREA":"으응...... 그, 그렇네.","JPN":"あ、うん……そ、そうだね。","ENG":"Yeah... I-I guess.","TWN":"嗯......好像是哦。"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"RAY_SCHOOL_NPC_NULL","text":{"KOREA":"그치만 내가 고득점을 받을 수 있을까......?","JPN":"でも僕が高得点を取れるのかな……？","ENG":"But... do you think I can really score that high?","TWN":"但是我能得到高分嗎……？"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L22_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"자신감을 가져야죠! 미나랑 호흡도 잘 맞았잖아요!","JPN":"自信を持ってください！　この前ミナちゃんと息ピッタリだったでしょう？","ENG":"Have a little more confidence! You made a great team with Mina in the simulator, remember?","TWN":"自信點好不好！你和米娜的配合也很好！"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAY_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L24_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"단, 훈련은 어디까지나 훈련이라는 사실을 명심하세요.","JPN":"ただし、訓練はあくまで訓練ということだけは忘れないでくださいね。","ENG":"But remember, at the end of the day, this is just training.","TWN":"但是一定要銘記，訓練只是訓練而已。"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"여러분이 소중히 해야 할 것은 성적보다 자신의, 그리고 옆에 있는 학우의 안전이에요.","JPN":"皆様が大事にすべきことは成績よりも自身の、そして隣にいる友人の安全です。","ENG":"Don't forget the safety of you and your classmates comes first, even before your training score.","TWN":"對大家來說最寶貴的不是成績，而是自己以及身邊同學的安全。"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"돌발 상황을 막기 위해 훈련 장소는 자율 방어 시스템으로 보호하고 있습니다.","JPN":"突発的な状況を防ぐため、訓練場所は自律防御システムによって守られています。","ENG":"In order to prepare against contingencies, the training area is protected by the Autonomous Defense System.","TWN":"為了應對突發情況，訓練場所設有自主防禦系統。"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"자율 방어 시스템에 대해서는 제작자인 이디스 양이 설명해 줄 거예요.","JPN":"自律防御システムについては、製作者であるイーディスが説明します。","ENG":"Edith, the engineer behind ADS, will now brief you on the system.","TWN":"關於自主防禦系統將由開發者伊蒂絲小姐進行講解。"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"쿠울......","JPN":"すやすや……","ENG":"Zzz...","TWN":"呼呼……"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"음냐...... 인공지능...... 최고......","JPN":"むにゃ…人工知能……最高ぅ……","ENG":"Zzz... A.I... For the win...","TWN":"唔……人工智慧……最棒……"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"이디스, 일어나세요.","JPN":"イーディス、起きてください。","ENG":"Wake up, Edith.","TWN":"伊蒂絲，快醒醒。"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"흐아암...... 벌써 내 차례야......?","JPN":"ふあぁ～もう私の番なの……？","ENG":"*Yawn*... Is it my turn already?","TWN":"（哈氣）……這麼快就輪到我了……？"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L34_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"그런데 무슨 얘기를 하러 왔더라......?","JPN":"えーと、何の話だっけぇ……？","ENG":"What was I supposed to talk about again?","TWN":"接著我要說什麼……？"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"자율 방어 시스템에 대해서였죠.","JPN":"自律防御システムについてです。","ENG":"The ADS.","TWN":"是自主防禦系統。"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"맞다아~","JPN":"そうだったー！","ENG":"Oh, right.","TWN":"對哦~"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"흠냐, 자율 방어 시스템은 내가 만든 인공지능 로봇들이야.","JPN":"むにゃあ……自律防御システムは私が作った人工知能ロボットだよぉ。","ENG":"The Autonomous Defense System is a collection of A.I. robots I designed.","TWN":"自主防禦系統是我開發的人工智慧機器人。"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"침식체들이 오지 않게 막아 주기도 하지만, 훈련 장소 밖으로 나가려는 사람들을 막아 주기도 해.","JPN":"侵食体たちが来ないように防ぐ機能もあるけど、訓練場所の外に出る人を止める機能もある。","ENG":"They not only keep unwanted C.O.s out of the training area, but also prevent folks from leaving the area.","TWN":"不僅能抵禦侵蝕體的進入，還能防止學院脫離訓練場所。"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"이제 됐지? 하암~","JPN":"もういいよね？　ふあ～。","ENG":"That about covers it, right? *Yawn*...","TWN":"就是這樣吧？（哈氣~）"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"네, 고생했어요. 푹 쉬도록 하세요.","JPN":"はい、お疲れ様です。もう休んでいいです。","ENG":"Yes, that'll do. Thanks. You can go back to sleep now.","TWN":"好吧，辛苦你了。你繼續休息吧。"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"방금 들으신 대로, 훈련 도중 자율 방어 시스템을 만나면 안내에 따라 주시길 바랍니다.","JPN":"今聞いたとおり、訓練途中に自律防御システムに出会ったら案内に従ってください。","ENG":"As you just heard, please comply with the instructions if you run into the ADS during training.","TWN":"就像剛才聽到的那樣，如果訓練過程中遇到自主防禦系統請遵守指示行動。"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"마지막으로, 위험한 상황에 처하면 학생회 임원이나 다른 선생님께 도움을 요청하세요.","JPN":"最後に、危険な状況に置かれたら躊躇せず生徒会役員や他の先生に助けを求めてください。","ENG":"Lastly, if you think you're in danger, please request immediate assistance from the Student Council officers or the faculty on site.","TWN":"最後，如果遇到危險情況，一定要向學生會管理人員或老師求助。"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"마침 목적지에 도착한 모양이군요.","JPN":"ちょうど目的地に到着したようですね。","ENG":"Looks like we've arrived at the destination.","TWN":"看來已經到達目的地了。"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"브리핑은 여기까지예요. 여러분의 건투를 빕니다.","JPN":"説明はここまでです。皆様のご健闘を祈ります。","ENG":"That's the end of my brief. Good luck, everyone.","TWN":"講解就到此為止，希望大家竭盡全力。"},"stage":{"bg":"PROLOGUE_02","bgm":"BATTLE_NORMAL_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};